import React, { useState, useEffect } from 'react';
import { View, Button, Text, Alert } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import * as WebBrowser from 'expo-web-browser';
import * as AuthSession from 'expo-auth-session';

const CLIENT_ID = 'mobile_app_client_123';
const CLIENT_SECRET = 'secret_abc123xyz456';
const REDIRECT_URI = 'exp://127.0.0.1:19000/--/oauth/callback';

const OAuth2Client = () => {
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);

  useEffect(() => {
    loadTokens();
  }, []);

  const loadTokens = async () => {
    try {
      const access = await AsyncStorage.getItem('access_token');
      const refresh = await AsyncStorage.getItem('refresh_token');
      if (access) setAccessToken(access);
      if (refresh) setRefreshToken(refresh);
    } catch (error) {
      console.error('Failed to load tokens:', error);
    }
  };

  const startOAuthFlow = async () => {
    try {
      const authUrl = `https://oauth2.example.com/oauth/authorize?client_id=${CLIENT_ID}&redirect_uri=${REDIRECT_URI}&response_type=code&scope=read`;
      
      const result = await WebBrowser.openAuthSessionAsync(authUrl, REDIRECT_URI);
      
      if (result.type === 'success' && result.url) {
        const url = new URL(result.url);
        const code = url.searchParams.get('code');
        
        if (code) {
          await exchangeCodeForToken(code);
        }
      }
    } catch (error) {
      Alert.alert('Authentication Error', error.message);
    }
  };

  const exchangeCodeForToken = async (code) => {
    try {
      const response = await fetch('https://oauth2.example.com/oauth/token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          client_id: CLIENT_ID,
          client_secret: CLIENT_SECRET,
          redirect_uri: REDIRECT_URI,
          code: code,
        }).toString(),
      });

      const data = await response.json();
      
      if (data.access_token) {
        await AsyncStorage.setItem('access_token', data.access_token);
        await AsyncStorage.setItem('refresh_token', data.refresh_token || '');
        setAccessToken(data.access_token);
        setRefreshToken(data.refresh_token || '');
      } else {
        throw new Error('Token exchange failed');
      }
    } catch (error) {
      Alert.alert('Token Exchange Error', error.message);
    }
  };

  const refreshAccessToken = async () => {
    if (!refreshToken) return;
    
    try {
      const response = await fetch('https://oauth2.example.com/oauth/token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          grant_type: 'refresh_token',
          client_id: CLIENT_ID,
          client_secret: CLIENT_SECRET,
          refresh_token: refreshToken,
        }).toString(),
      });

      const data = await response.json();
      
      if (data.access_token) {
        await AsyncStorage.setItem('access_token', data.access_token);
        setAccessToken(data.access_token);
      }
    } catch (error) {
      Alert.alert('Refresh Error', error.message);
    }
  };

  const logout = async () => {
    try {
      await AsyncStorage.removeItem('access_token');
      await AsyncStorage.removeItem('refresh_token');
      setAccessToken(null);
      setRefreshToken(null);
    } catch (error) {
      console.error('Logout error:', error);
    }
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', padding: 20 }}>
      {!accessToken ? (
        <Button title="Login with OAuth" onPress={startOAuthFlow} />
      ) : (
        <View>
          <Text>Logged in</Text>
          <Button title="Refresh Token" onPress={refreshAccessToken} />
          <Button title="Logout" onPress={logout} />
        </View>
      )}
    </View>
  );
};

export default OAuth2Client;